    if (v === undefined || v === null || v === "") return null;
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function toInt(v) {
    const n = toNum(v);
    return n === null ? null : Math.trunc(n);
}

function toBool(v) {
